# Infrastructure-level: IAM policy example (AWS-style pseudocode)
CUSTOMER_SUPPORT_AGENT_POLICY = {
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "dynamodb:GetItem",           # Read orders
                "dynamodb:Query",             # List orders by customer
            ],
            "Resource": "arn:aws:dynamodb:*:*:table/orders",
            "Condition": {
                # Restrict to the agent's own customer partition key
                "ForAllValues:StringEquals": {
                    "dynamodb:LeadingKeys": ["${agent:CustomerId}"]
                }
            }
        },
        {
            "Effect": "Allow",
            "Action": ["s3:GetObject"],
            "Resource": "arn:aws:s3:::support-docs/*"
        }
        # NOT included: s3:PutObject, s3:DeleteObject, dynamodb:PutItem,
        # dynamodb:DeleteItem, iam:*, ec2:*, rds:*
    ]
}

# Application-level: least-privilege DB connection
def get_readonly_db_connection(db_config: dict):
    """
    Always use a read-only replica and a read-only user for agents that
    only need to query. Never reuse the admin or read-write connection.
    """
    import psycopg2
    return psycopg2.connect(
        host=db_config["readonly_host"],   # replica, not primary
        dbname=db_config["dbname"],
        user=db_config["readonly_user"],   # SELECT-only role
        password=db_config["readonly_password"],
    )

class ContextBoundEmailTool:
    def __init__(self, session_user_email: str):
        # Tool can only email the session owner — enforced in constructor
        self._allowed_recipient = session_user_email

    def __call__(self, to: str, subject: str, body: str) -> str:
        if to != self._allowed_recipient:
            raise PermissionError(
                f"This agent may only send email to {self._allowed_recipient!r}. "
                f"Attempted: {to!r}"
            )
        return _send_email_impl(to, subject, body)

from dataclasses import dataclass
from enum import Enum, auto
from typing import Callable, Any

class ActionImpact(Enum):
    REVERSIBLE   = auto()   # can be undone (read, soft-delete with restore)
    IRREVERSIBLE = auto()   # cannot be undone (hard-delete, send, publish, pay)

@dataclass
class PlannedAction:
    tool_name: str
    args: dict[str, Any]
    impact: ActionImpact
    description: str         # human-readable for approval UI

class AutonomyGatedExecutor:
    def __init__(
        self,
        dispatcher,
        human_confirm: Callable[[PlannedAction], bool],
    ):
        self._dispatcher = dispatcher
        self._confirm = human_confirm

    def execute(self, action: PlannedAction) -> Any:
        if action.impact == ActionImpact.IRREVERSIBLE:
            confirmed = self._confirm(action)
            if not confirmed:
                raise PermissionError(
                    f"Human rejected planned action: {action.description}"
                )
        return self._dispatcher.dispatch(action.tool_name, action.args, human_approved=True)

# Example usage
def mock_human_confirm(action: PlannedAction) -> bool:
    print(f"[APPROVAL REQUIRED] {action.description}")
    response = input("Approve? (y/n): ").strip().lower()
    return response == "y"

executor = AutonomyGatedExecutor(dispatcher, human_confirm=mock_human_confirm)

# Anti-pattern: sub-agent gets parent credentials
def spawn_sub_agent(task: str, parent_context: dict) -> SubAgent:
    return SubAgent(
        task=task,
        db_conn=parent_context["admin_db_conn"],  # full admin — DANGEROUS
        api_keys=parent_context["api_keys"],       # all keys — DANGEROUS
    )

# Correct: derive minimal credentials for each sub-agent's task
def spawn_sub_agent_safe(task: str, db_pool) -> SubAgent:
    return SubAgent(
        task=task,
        db_conn=db_pool.get_readonly_connection(),  # narrowest scope
        api_keys={},  # no API keys unless this task actually needs them
    )
